import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// Angular `data` is NOT inherited by child routes — `flow` is repeated on each child.
export const routes: Routes = ([
  { path: '', redirectTo: 'login', pathMatch: 'full' },

  {
    path: 'login',
    loadComponent: () => import('./features/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['signup', 'projects'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./features/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', entry: true, edgesTo: ['login', 'projects'], label: 'Sign up' } },
  },

  {
    path: 'projects',
    loadComponent: () =>
      import('./features/projects/projects-list.component').then((m) => m.ProjectsListComponent),
    canActivate: [authGuard],
    data: {
      flow: {
        flowId: 'projects',
        node: 'projects',
        showInNavbar: true,
        label: 'Projects',
        scope: 'all',
        edgesTo: ['project-dashboard', 'login'],
      },
    },
  },

  {
    path: 'projects/:id',
    loadComponent: () =>
      import('./features/project/project-shell.component').then((m) => m.ProjectShellComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'project-shell', node: 'project-shell', label: 'Project', edgesTo: ['project-dashboard'] } },
    children: [
      { path: '', redirectTo: 'dashboard', pathMatch: 'full' },
      {
        path: 'dashboard',
        loadComponent: () =>
          import('./features/project/dashboard/dashboard.component').then((m) => m.DashboardComponent),
        canActivate: [authGuard],
        data: {
          flow: {
            flowId: 'project-dashboard',
            node: 'project-dashboard',
            label: 'Dashboard',
            edgesTo: ['project-schedule', 'project-milestones', 'project-budget', 'project-siteplan'],
          },
        },
      },
      {
        path: 'schedule',
        loadComponent: () =>
          import('./features/project/schedule/gantt.component').then((m) => m.GanttComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'project-schedule', node: 'project-schedule', label: 'Schedule', edgesTo: ['project-dashboard'] } },
      },
      {
        path: 'milestones',
        loadComponent: () =>
          import('./features/project/milestones/milestones.component').then((m) => m.MilestonesComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'project-milestones', node: 'project-milestones', label: 'Milestones', edgesTo: ['project-dashboard'] } },
      },
      {
        path: 'budget',
        loadComponent: () =>
          import('./features/project/budget/budget.component').then((m) => m.BudgetComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'project-budget', node: 'project-budget', label: 'Budget', edgesTo: ['project-dashboard'] } },
      },
      {
        path: 'siteplan',
        loadComponent: () =>
          import('./features/project/siteplan/siteplan.component').then((m) => m.SiteplanComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'project-siteplan', node: 'project-siteplan', label: 'Site Plan', edgesTo: ['project-dashboard'] } },
      },
    ],
  },

  {
    path: 'admin/settings',
    loadComponent: () =>
      import('./features/admin/admin-settings.component').then((m) => m.AdminSettingsComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'admin-settings', node: 'admin-settings', showInNavbar: true, label: 'Admin', scope: 'admin', edgesTo: ['projects'] } },
  },

  { path: '**', redirectTo: 'login' },
] satisfies FlowRoute[]) as Routes;
